    const n = nums.length;
    for (let p = 1; p < n - 1; p++) {
        for (let q = p + 1; q < n - 1; q++) {
            // Check first part: 0...p is strictly increasing
            let valid = true;
            for (let i = 0; i < p; i++) {
                if (nums[i] >= nums[i + 1]) {
                    valid = false;
                    break;
                }
            }
            if (!valid) continue;

            // Check middle part: p...q is strictly decreasing
            valid = true;
            for (let i = p; i < q; i++) {
                if (nums[i] <= nums[i + 1]) {
                    valid = false;
                    break;
                }
            }
            if (!valid) continue;

